import{_ as i,o as l,c as s,a2 as n}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"认知走查","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/03-validation/03-cognitive-walkthrough.md","filePath":"03-interaction-design/notes/03-validation/03-cognitive-walkthrough.md","lastUpdated":null}'),e={name:"03-interaction-design/notes/03-validation/03-cognitive-walkthrough.md"};function t(r,a,h,p,d,o){return l(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="认知走查" tabindex="-1">认知走查 <a class="header-anchor" href="#认知走查" aria-label="Permalink to &quot;认知走查&quot;">​</a></h1><p>认知走查是一种以任务为中心的可用性检查方法。检查者从目标用户的已有知识出发，逐步判断用户是否会形成正确子目标、发现并理解正确动作，以及操作后能否从反馈知道自己正在接近目标。它特别适合检查初次或低频使用的可学习性。</p><h2 id="方法边界" tabindex="-1">方法边界 <a class="header-anchor" href="#方法边界" aria-label="Permalink to &quot;方法边界&quot;">​</a></h2><p>认知走查可以发现：</p><ul><li>入口或正确动作不可发现；</li><li>标签、图标与用户目标难以关联；</li><li>步骤依赖隐藏知识；</li><li>操作反馈不足，用户不知道是否前进；</li><li>错误后无法形成下一步。</li></ul><p>它不能单独证明：</p><ul><li>问题在真实用户中的发生率；</li><li>熟练用户长期效率；</li><li>视觉、性能、可访问性和业务规则全部合格；</li><li>检查者对目标用户知识的假设正确。</li></ul><p>没有条件开展用户访谈时，可以用已有研究、公开支持问题、帮助文档、任务日志和产品证据建立初始知识假设，并明确标记未知项。</p><h2 id="四个核心问题" tabindex="-1">四个核心问题 <a class="header-anchor" href="#四个核心问题" aria-label="Permalink to &quot;四个核心问题&quot;">​</a></h2><p>对流程中的每一个动作，依次判断：</p><ol><li><strong>用户会尝试达成正确的子目标吗？</strong></li><li><strong>用户会注意到正确的操作入口吗？</strong></li><li><strong>用户会把这个入口与想要的结果联系起来吗？</strong></li><li><strong>执行后，用户会从反馈知道自己取得了进展吗？</strong></li></ol><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G[&quot;当前目标&quot;] --&gt; Q1{&quot;形成正确子目标？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q1 --&gt; Q2{&quot;发现正确动作？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q2 --&gt; Q3{&quot;理解动作与结果？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q3 --&gt; A[&quot;执行动作&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; Q4{&quot;反馈表明正确进展？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q4 --&gt; G</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>任一问题回答“否”或“未知”，都记录证据、可能失败过程和需要补充的验证，不直接把设计判为整体不可用。</p><h2 id="准备材料" tabindex="-1">准备材料 <a class="header-anchor" href="#准备材料" aria-label="Permalink to &quot;准备材料&quot;">​</a></h2><h3 id="目标用户知识假设" tabindex="-1">目标用户知识假设 <a class="header-anchor" href="#目标用户知识假设" aria-label="Permalink to &quot;目标用户知识假设&quot;">​</a></h3><p>记录：</p><ul><li>用户熟悉的对象、术语和平台惯例；</li><li>是否使用过相似功能；</li><li>当前能看到和持有什么信息；</li><li>可能不知道的权限、规则和状态；</li><li>输入设备、辅助技术与环境约束。</li></ul><p>“普通用户知道齿轮代表设置”是不充分假设。应写“首次项目编辑者曾使用浏览器表单，但没有接触过本产品的‘自动化规则’术语”。</p><h3 id="任务" tabindex="-1">任务 <a class="header-anchor" href="#任务" aria-label="Permalink to &quot;任务&quot;">​</a></h3><p>任务包含现实目标、触发、入口、前置条件、固定输入和可观察完成标准。不要把界面步骤写进任务提示，否则会泄露走查答案。</p><p>错误任务：“点击更多，再选择导出”。正确任务：“把当前项目的全部任务导出为 CSV，以便离线核对负责人。”</p><h3 id="正确动作序列" tabindex="-1">正确动作序列 <a class="header-anchor" href="#正确动作序列" aria-label="Permalink to &quot;正确动作序列&quot;">​</a></h3><p>由当前产品真实行为确定，包括分支、状态、等待和恢复。若存在多个正确路径，分别走查或说明选择依据。</p><h2 id="每一步怎样记录" tabindex="-1">每一步怎样记录 <a class="header-anchor" href="#每一步怎样记录" aria-label="Permalink to &quot;每一步怎样记录&quot;">​</a></h2><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### 步骤 N：动作名称</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 当前界面与状态：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 用户当前目标：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 正确动作：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Q1 子目标：是/否/未知；证据</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Q2 发现：是/否/未知；证据</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Q3 关联：是/否/未知；证据</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Q4 反馈：是/否/未知；证据</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 失败过程：用户可能做什么，结果是什么</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 问题严重性：任务影响、恢复和风险</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 修复候选：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 待验证：</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>回答不能只写“是”。必须说明界面线索和用户知识怎样支持结论。</p><h2 id="走查中的证据" tabindex="-1">走查中的证据 <a class="header-anchor" href="#走查中的证据" aria-label="Permalink to &quot;走查中的证据&quot;">​</a></h2><h3 id="支持发现" tabindex="-1">支持发现 <a class="header-anchor" href="#支持发现" aria-label="Permalink to &quot;支持发现&quot;">​</a></h3><p>入口在用户关注区域、具有可见文字、与任务对象相邻、键盘可达、没有被折叠或遮挡。</p><h3 id="支持关联" tabindex="-1">支持关联 <a class="header-anchor" href="#支持关联" aria-label="Permalink to &quot;支持关联&quot;">​</a></h3><p>动作名称使用用户任务语言，结果对象明确，图标有标签，当前状态解释了为什么此时可用。</p><h3 id="支持进展反馈" tabindex="-1">支持进展反馈 <a class="header-anchor" href="#支持进展反馈" aria-label="Permalink to &quot;支持进展反馈&quot;">​</a></h3><p>操作后状态、对象、进度和下一步明确；动态变化可被辅助技术获知；等待与最终完成分开。</p><h3 id="反证" tabindex="-1">反证 <a class="header-anchor" href="#反证" aria-label="Permalink to &quot;反证&quot;">​</a></h3><p>公开帮助反复解释同一入口、任务观察中用户进入错误页面、相同图标在产品内含义不同、操作后产生重复请求等。</p><h2 id="完整案例-首次设置双重验证" tabindex="-1">完整案例：首次设置双重验证 <a class="header-anchor" href="#完整案例-首次设置双重验证" aria-label="Permalink to &quot;完整案例：首次设置双重验证&quot;">​</a></h2><h3 id="具体任务与知识假设" tabindex="-1">具体任务与知识假设 <a class="header-anchor" href="#具体任务与知识假设" aria-label="Permalink to &quot;具体任务与知识假设&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>角色：首次设置账户安全的用户</span></span>
<span class="line"><span>目标：启用验证器应用，以便登录时使用一次性验证码</span></span>
<span class="line"><span>入口：账户设置 &gt; 安全</span></span>
<span class="line"><span>输入：已安装验证器应用，当前会话有效</span></span>
<span class="line"><span>完成：账户状态显示已启用；恢复代码已安全保存；重新登录可验证</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>假设用户理解“账户”“安全”和“验证码”，但不知道 TOTP、二维码密钥、恢复代码的具体作用。这些是假设，需要公开帮助、支持记录或任务观察补证。</p><h3 id="正确流程" tabindex="-1">正确流程 <a class="header-anchor" href="#正确流程" aria-label="Permalink to &quot;正确流程&quot;">​</a></h3><ol><li>在安全页选择“双重验证”。</li><li>选择“验证器应用”。</li><li>扫描二维码或手动输入密钥。</li><li>输入六位验证码并验证。</li><li>保存恢复代码并确认。</li><li>查看“已启用”结果。</li></ol><h3 id="步骤-1-走查" tabindex="-1">步骤 1 走查 <a class="header-anchor" href="#步骤-1-走查" aria-label="Permalink to &quot;步骤 1 走查&quot;">​</a></h3><ul><li>当前状态：安全页同时有密码、会话、双重验证和登录通知。</li><li>Q1：用户会形成“找到双重验证设置”的子目标，因为目标直接对应安全设置。</li><li>Q2：入口位于“登录安全”组，有可见文本，不依赖图标，支持发现。</li><li>Q3：入口文案“双重验证”与目标一致；若产品其他位置只用“2FA”，关联会降低。</li><li>Q4：进入后标题为“设置双重验证”，面包屑保留账户安全，明确进展。</li></ul><h3 id="步骤-3-走查" tabindex="-1">步骤 3 走查 <a class="header-anchor" href="#步骤-3-走查" aria-label="Permalink to &quot;步骤 3 走查&quot;">​</a></h3><ul><li>当前状态：页面显示二维码、手动密钥和“下一步”。</li><li>Q1：用户需要把账户加入验证器，但可能不知道必须打开外部应用。</li><li>Q2：二维码明显，但“手动密钥”是折叠链接；相机不可用用户可能找不到替代路径。</li><li>Q3：说明写“扫描此二维码”，能关联扫码；但未说明二维码包含敏感密钥，不应截图分享。</li><li>Q4：扫描发生在外部应用，本页面没有自动反馈；用户需要知道“应用出现六位代码后返回本页”。</li></ul><p>问题 CW-03：外部渠道转换的进展反馈不足。修复候选是用步骤文本明确“在验证器中添加账户 → 出现六位代码 → 回到此页输入”，并始终提供可键盘访问的手动密钥方式。</p><h3 id="步骤-5-走查" tabindex="-1">步骤 5 走查 <a class="header-anchor" href="#步骤-5-走查" aria-label="Permalink to &quot;步骤 5 走查&quot;">​</a></h3><ul><li>当前状态：验证码通过后显示 10 个恢复代码和“完成”。</li><li>Q1：用户可能认为验证码通过已经完成，不会形成保存恢复代码子目标。</li><li>Q2：下载与复制按钮可见，但主要按钮“完成”视觉更强。</li><li>Q3：文案“以后无法登录时使用”支持关联，但未说明每个代码一次性和应离线保存。</li><li>Q4：复制后出现“已复制 10 个恢复代码”，但复制不证明用户安全保存。</li></ul><p>问题 CW-05：主操作顺序与安全恢复目标冲突。候选方案是在进入最终完成前要求用户确认已保存，并提供复制、下载和打印等可访问方式；不能把复选框当作安全保存的证明。</p><h3 id="输出摘要" tabindex="-1">输出摘要 <a class="header-anchor" href="#输出摘要" aria-label="Permalink to &quot;输出摘要&quot;">​</a></h3><table tabindex="0"><thead><tr><th>步骤</th><th>主要失败问题</th><th>影响</th><th>证据强度</th></tr></thead><tbody><tr><td>找入口</td><td>术语若只用 2FA 会降低关联</td><td>可能找不到</td><td>待对照产品文案</td></tr><tr><td>扫二维码</td><td>外部应用与返回步骤不清</td><td>中断流程</td><td>当前界面事实</td></tr><tr><td>输入验证码</td><td>错误未说明时钟偏差或重试</td><td>无法恢复</td><td>需制造错误</td></tr><tr><td>保存恢复代码</td><td>“完成”早于恢复准备</td><td>未来锁定账户</td><td>当前层级事实</td></tr></tbody></table><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><ul><li>验证码错误：保留输入上下文，说明代码过期或错误，并允许新代码重试。</li><li>二维码无法扫描：手动密钥始终可发现且可复制，不能只悬停显示。</li><li>会话过期：重新认证后返回设置步骤，不暴露密钥给未授权会话。</li><li>恢复代码下载失败：代码仍可复制或重新生成；重新生成使旧代码失效并明确结果。</li></ul><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ol><li>使用没有产品经验但具备假设知识的走查角色重新回答四问。</li><li>仅用键盘完成，检查二维码替代、复制、错误和对话框焦点。</li><li>用屏幕阅读器核对步骤、密钥说明、验证码错误和最终状态。</li><li>制造错误码、会话过期和下载失败。</li><li>与可用性任务观察或支持问题对照，检验知识假设与预测。</li></ol><h2 id="记录严重性" tabindex="-1">记录严重性 <a class="header-anchor" href="#记录严重性" aria-label="Permalink to &quot;记录严重性&quot;">​</a></h2><p>使用任务影响、发生条件、恢复成本和风险描述，不只给 1–5 分。例如：“首次设置者在外部应用返回点可能中断；没有替代认证时会阻止启用；可返回上一步恢复；涉及账户安全，需在发布前验证。”</p><h2 id="常见错误与修正" tabindex="-1">常见错误与修正 <a class="header-anchor" href="#常见错误与修正" aria-label="Permalink to &quot;常见错误与修正&quot;">​</a></h2><ul><li>把检查者本人当目标用户：先写知识与环境假设。</li><li>任务提示包含按钮名和步骤：只写目标与完成标准。</li><li>每一步只回答“是”：补界面线索和反证。</li><li>只走主路径：加入错误、权限、取消和恢复。</li><li>发现问题后直接猜原因：标记推断并补证据。</li><li>用认知走查替代键盘、WCAG、性能和工程测试。</li><li>把方法输出当真实发生率：需行为数据或任务观察。</li></ul><h2 id="可执行步骤" tabindex="-1">可执行步骤 <a class="header-anchor" href="#可执行步骤" aria-label="Permalink to &quot;可执行步骤&quot;">​</a></h2><ol><li>固定产品版本、角色、任务、输入和完成标准。</li><li>写目标用户已有知识及证据，未知项标假设。</li><li>还原一条或多条正确动作序列。</li><li>对每一步回答四个核心问题并记录证据。</li><li>写用户可能的失败过程、影响和恢复。</li><li>加入无效输入、无权限、等待、中断和返回。</li><li>合并相同机制问题，形成修复候选与验证计划。</li><li>用任务观察、日志或支持证据检验预测，不夸大发生率。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>对“首次从项目导出 CSV”执行认知走查。</p><p>完成时应满足：</p><ul><li>任务不泄露入口和按钮名称；</li><li>用户知识假设有来源或明确为未知；</li><li>至少走查 6 个动作，每步完整回答四问；</li><li>覆盖入口、范围选择、生成中、下载、错误和过期；</li><li>记录键盘与屏幕阅读器相关线索；</li><li>每个问题有失败过程、影响、修复和待验证项；</li><li>结论只说明潜在可学习性问题，不声称真实发生率。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.ics.uci.edu/~redmiles/ics104-WQ06/Chapter_4/CognitiveWalkthroughRev2006.pdf" target="_blank" rel="noreferrer">Wharton、Rieman、Lewis、Polson：The Cognitive Walkthrough Method</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/predictable.html" target="_blank" rel="noreferrer">W3C WAI：Understanding Guideline 3.2 Predictable</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/input-assistance.html" target="_blank" rel="noreferrer">W3C WAI：Understanding Guideline 3.3 Input Assistance</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/design/making-prototypes" target="_blank" rel="noreferrer">GOV.UK Service Manual：Making prototypes</a>（访问日期：2026-07-17）</li></ul>`,67)])])}const k=i(e,[["render",t]]);export{u as __pageData,k as default};
